patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..c758570c5c46 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3714,6 +3714,22 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (Instruction *Mul = foldSelectZeroOrMul(SI, *this))
     return Mul;

+  // Fold select of symmetric selects:
+  //   select C2, (select C1, X, Y), (select C1, Y, X) -> select (xor C1, C2), Y, X
+  //   select C2, (select C1, Y, X), (select C1, X, Y) -> select (xor C1, C2), X, Y
+  if (auto *TrueSel = dyn_cast<SelectInst>(TrueVal))
+    if (auto *FalseSel = dyn_cast<SelectInst>(FalseVal))
+      if (TrueSel->getCondition() == FalseSel->getCondition() &&
+          TrueSel->getCondition()->getType() == CondVal->getType() &&
+          TrueSel->getTrueValue() == FalseSel->getFalseValue() &&
+          TrueSel->getFalseValue() == FalseSel->getTrueValue() &&
+          TrueSel->getTrueValue() != TrueSel->getFalseValue() &&
+          TrueSel->hasOneUse() && FalseSel->hasOneUse()) {
+        Value *Xor = Builder.CreateXor(TrueSel->getCondition(), CondVal);
+        return SelectInst::Create(Xor, TrueSel->getFalseValue(),
+                                  TrueSel->getTrueValue());
+      }
+
   // Turn (select C, (op X, Y), (op X, Z)) -> (op X, (select C, Y, Z))
   auto *TI = dyn_cast<Instruction>(TrueVal);
   auto *FI = dyn_cast<Instruction>(FalseVal);

